#include <string>
#include <regex>

std::string markdown_to_html(const std::string& markdown) {
    // Replace headings (#, ##, ##...)
    std::regex heading_regex("#+\\s+");
    std::string heading_html;
    std::string::const_iterator heading_iter = std::sregex_iterator(markdown.begin(), markdown.end(), heading_regex));
    std::sregex_iterator heading_end = std::sregex_iterator();
    for (std::sregex_iterator i = heading_iter; i != heading_end; ++i) {
        std::smatch heading_match = *i;
        size_t heading_level = heading_match[0].length();
        heading_html = "<h" + std::to_string(heading_level) + ">" + heading_match[0].str().substr(1) + "</h" + std::to_string(heading_level) + ">";
        markdown.replace(heading_match[0].start(), heading_match[0].length(), heading_html);
    }

    // Replace bold (*word*)
    std::regex bold_regex("\\*([^\\*]+)\\*");
    markdown = std::regex_replace(markdown, bold_regex, "<strong>\\1</strong>");

    // Replace italic (_word_)
    std::regex italic_regex("(_[^_]+)_");
    markdown = std::regex_replace(markdown, italic_regex, "<em>\\1</em>");

    // Replace links ([word](url)))
    std::regex link_regex("\\[([^\\[]+)]\\(([^\\(]+)\\))");
    markdown = std::regex_replace(markdown, link_regex, "<a href=\"\\2\">\\1</a>");

    // Replace paragraphs (two or more newlines between paragraphs)
    std::regex paragraph_regex("(?:\\r\\n|\\r|\\n){2,} +)");
    std::string paragraph_html;
    std::string::const_iterator paragraph_iter = std::sregex_iterator(markdown.begin(), markdown.end(), paragraph_regex));
    std::sregex_iterator paragraph_end = std::sregex_iterator();
    for (std::sregex_iterator i = paragraph_iter; i != paragraph_end; ++i) {
        std::smatch paragraph_match = *i;
        paragraph_html = "<p>" + paragraph_match[0].str() + "</p>";
        markdown.replace(paragraph_match[0].start(), paragraph_match[0].length(), paragraph_html);
    }

    return markdown;
}
```

